  public static final Discriminator UPDATE_FEES_AND_REWARDS_DISCRIMINATOR = toDiscriminator(154, 230, 250, 13, 236, 209, 75, 223);

  /// Update accrued fees and rewards for an Orca Whirlpools position.
  /// 
  /// - Permission: `UpdateFeesAndRewards`.
  /// - Policy: Whirlpool and both pool token mints must be allowlisted.
  ///
  public static List<AccountMeta> updateFeesAndRewardsKeys(final SolanaAccounts solanaAccounts,
                                                           final PublicKey glamStateKey,
                                                           final PublicKey glamVaultKey,
                                                           final PublicKey glamSignerKey,
                                                           final PublicKey integrationAuthorityKey,
                                                           final PublicKey cpiProgramKey,
                                                           final PublicKey glamProtocolProgramKey,
                                                           final PublicKey whirlpoolKey,
                                                           final PublicKey positionKey,
                                                           final PublicKey tickArrayLowerKey,
                                                           final PublicKey tickArrayUpperKey) {
    return List.of(
      createWrite(glamStateKey),
      createWrite(glamVaultKey),
      createWritableSigner(glamSignerKey),
      createRead(integrationAuthorityKey),
      createRead(cpiProgramKey),
      createRead(glamProtocolProgramKey),
      createRead(solanaAccounts.systemProgram()),
      createWrite(whirlpoolKey),
      createWrite(positionKey),
      createRead(tickArrayLowerKey),
      createRead(tickArrayUpperKey)
    );
  }

  /// Update accrued fees and rewards for an Orca Whirlpools position.
  /// 
  /// - Permission: `UpdateFeesAndRewards`.
  /// - Policy: Whirlpool and both pool token mints must be allowlisted.
  ///
  public static Instruction updateFeesAndRewards(final AccountMeta invokedExtOrcaProgramMeta,
                                                 final SolanaAccounts solanaAccounts,
                                                 final PublicKey glamStateKey,
                                                 final PublicKey glamVaultKey,
                                                 final PublicKey glamSignerKey,
                                                 final PublicKey integrationAuthorityKey,
                                                 final PublicKey cpiProgramKey,
                                                 final PublicKey glamProtocolProgramKey,
                                                 final PublicKey whirlpoolKey,
                                                 final PublicKey positionKey,
                                                 final PublicKey tickArrayLowerKey,
                                                 final PublicKey tickArrayUpperKey) {
    final var keys = updateFeesAndRewardsKeys(
      solanaAccounts,
      glamStateKey,
      glamVaultKey,
      glamSignerKey,
      integrationAuthorityKey,
      cpiProgramKey,
      glamProtocolProgramKey,
      whirlpoolKey,
      positionKey,
      tickArrayLowerKey,
      tickArrayUpperKey
    );
    return updateFeesAndRewards(invokedExtOrcaProgramMeta, keys);
  }

  /// Update accrued fees and rewards for an Orca Whirlpools position.
  /// 
  /// - Permission: `UpdateFeesAndRewards`.
  /// - Policy: Whirlpool and both pool token mints must be allowlisted.
  ///
  public static Instruction updateFeesAndRewards(final AccountMeta invokedExtOrcaProgramMeta,
                                                 final List<AccountMeta> keys) {
    return Instruction.createInstruction(invokedExtOrcaProgramMeta, keys, UPDATE_FEES_AND_REWARDS_DISCRIMINATOR);
  }

